116	  async generateObject<TSchema, TOutput>(
117	    args: GenerateObjectArgs<TSchema>,
118	  ): Promise<OracleObjectResult<TOutput>> {
119	    const { plan, route, schema, providerOptions } = args;
120	    const { systemPrompt, userMessage } = flattenPlan(plan);
121	    const callStartedAt = Date.now();
122	
123	    const contents: Content[] = [{ role: 'user', parts: [{ text: userMessage }] }];
124	    const jsonSchema = zodToJsonSchema(schema);
125	    const commonConfig = {
126	      temperature: 0.1,
127	      // Output-token budget so a dense extraction doesn't truncate the JSON
128	      // (truncated JSON parses as a raw string and fails the schema).
129	      ...(typeof providerOptions?.maxOutputTokens === 'number'
130	        ? { maxOutputTokens: providerOptions.maxOutputTokens }
131	        : {}),
132	      ...geminiThinkingConfig(route),
133	    };
134	    const sdkConfig = {
135	      ...commonConfig,
136	      responseMimeType: 'application/json',
137	      responseJsonSchema: jsonSchema as unknown,
138	    };
139	    const restConfig = {
140	      ...commonConfig,
141	      responseMimeType: 'application/json',
142	      responseSchema: toGeminiRestSchema(jsonSchema),
143	    };
144	    const response = this.client
145	      ? await this.client.models.generateContent({
146	          model: route.modelId,
147	          contents,
148	          config: sdkConfig,
149	        })
150	      : await this.generateContentWithOAuth({
151	          modelId: route.modelId,
152	          contents,
153	          systemPrompt,
154	          generationConfig: restConfig,
155	        });
156	
157	    const text = extractTextFromGeminiResponse(response);
158	    const parsed = parseJsonOrRaw(text);
159	    const validated = tryZodParse<TOutput>(schema, parsed);
160	
161	    return {
162	      object: (validated ?? parsed) as TOutput,
163	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
164	      rawResponse: response,
165	    };
166	  }
