247	/**
248	 * Build the Gemini `thinkingConfig` for a route.
249	 *
250	 * Two gates, then the right FIELD SHAPE per model generation:
251	 *   1. `supportsReasoningControls` ‚Äî the model supports client thinking control
252	 *      at all (sourced from model_capabilities.thinking). If false, omit.
253	 *   2. `reasoningEffort` ‚Äî an effort was actually requested. If unset, omit.
254	 *   3. `route.geminiThinkingStyle` ‚Äî HOW this model generation expresses it,
255	 *      derived in the resolve/catalog layer (never hard-coded here):
256	 *        - 'thinking_budget' ‚Üí Gemini 2.x: numeric `thinkingConfig.thinkingBudget`.
257	 *          The 2.x generation 400s on the `thinkingLevel` enum ‚Äî this was the
258	 *          root cause of gemini-2.5-flash vision failing whenever an effort was
259	 *          set. Budgets mirror the Vertex adapter (off=0, low=1024, med=8192,
260	 *          high=24576 Flash cap).
261	 *        - 'thinking_level' ‚Üí Gemini 3.x+: `thinkingConfig.thinkingLevel` enum.
262	 *        - 'none'/undefined ‚Üí omit (treat as unsupported).
263	 */
264	function geminiThinkingConfig(route: OracleModelRoute):
265	  | { thinkingConfig: { thinkingLevel: ThinkingLevel } }
266	  | { thinkingConfig: { thinkingBudget: number } }
267	  | Record<string, never> {
268	  if (!route.supportsReasoningControls) return {};
269	  const effort = route.reasoningEffort;
270	  if (!effort) return {};
271	
272	  const style = route.geminiThinkingStyle ?? 'thinking_budget';
273	  if (style === 'none') return {};
274	
275	  if (style === 'thinking_level') {
276	    const thinkingLevel =
277	      effort === 'off' ? ThinkingLevel.MINIMAL
278	        : effort === 'low' ? ThinkingLevel.LOW
279	        : effort === 'medium' ? ThinkingLevel.MEDIUM
280	        : ThinkingLevel.HIGH;
281	    return { thinkingConfig: { thinkingLevel } };
282	  }
283	
284	  // thinking_budget (Gemini 2.x)
285	  const thinkingBudget =
286	    effort === 'off' ? 0
287	      : effort === 'low' ? 1024
288	      : effort === 'medium' ? 8192
289	      : 24576;
290	  return { thinkingConfig: { thinkingBudget } };
291	}
