293	function normalizeGeminiUsage(
294	  response: GenerateContentResponse,
295	  latencyMs: number,
296	): OracleUsage {
297	  const u = response.usageMetadata ?? {};
298	  return {
299	    inputTokens: u.promptTokenCount,
300	    outputTokens: u.candidatesTokenCount,
301	    cachedInputTokens: u.cachedContentTokenCount,
302	    reasoningTokens: u.thoughtsTokenCount,
303	    latencyMs,
304	    providerRequestId: response.responseId,
305	    rawUsageJson: u,
306	  };
307	}
