309	function extractTextFromGeminiResponse(response: GenerateContentResponse): string {
310	  if (typeof response.text === 'string') return response.text;
311	  const candidateText = response.candidates
312	    ?.flatMap((candidate) => candidate.content?.parts ?? [])
313	    .map((part) => ('text' in part && typeof part.text === 'string' ? part.text : ''))
314	    .join('');
315	  return candidateText ?? '';
316	}
