318	async function getGenerativeLanguageAccessToken(saJson: string): Promise<string> {
319	  const sa = parseServiceAccountJson(saJson);
320	  const now = Math.floor(Date.now() / 1000);
321	
322	  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
323	  const payload = Buffer.from(
324	    JSON.stringify({
325	      iss: sa.client_email,
326	      scope: 'https://www.googleapis.com/auth/generative-language',
327	      aud: 'https://oauth2.googleapis.com/token',
328	      iat: now,
329	      exp: now + 3600,
330	    }),
331	  ).toString('base64url');
332	
333	  const signer = createSign('SHA256');
334	  signer.update(`${header}.${payload}`);
335	  const sig = signer.sign({ key: sa.private_key, format: 'pem' }, 'base64url');
336	  const jwt = `${header}.${payload}.${sig}`;
337	
338	  const res = await fetch('https://oauth2.googleapis.com/token', {
339	    method: 'POST',
340	    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
341	    body: new URLSearchParams({
342	      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
343	      assertion: jwt,
344	    }),
345	    signal: AbortSignal.timeout(10_000),
346	  });
347	  if (!res.ok) {
348	    throw new Error(`Google token exchange failed: ${res.status} ${await res.text()}`);
349	  }
350	  const data = (await res.json()) as { access_token: string };
351	  return data.access_token;
352	}
353	
354	function parseServiceAccountJson(saJson: string): { client_email: string; private_key: string } {
355	  try {
356	    return JSON.parse(saJson) as { client_email: string; private_key: string };
357	  } catch {
358	    // Vercel env pulls can materialize the PEM as literal newlines inside the
359	    // JSON string. Normalize just that field, then parse normally.
360	    const normalized = saJson.replace(
361	      /"private_key"\s*:\s*"([\s\S]*?)"/,
362	      (_match, key: string) => `"private_key":"${key.replace(/\r?\n/g, '\\n')}"`,
363	    );
364	    return JSON.parse(normalized) as { client_email: string; private_key: string };
365	  }
366	}
