372	function toGeminiRestSchema(schema: unknown): unknown {
373	  if (Array.isArray(schema)) return schema.map(toGeminiRestSchema);
374	  if (!schema || typeof schema !== 'object') return schema;
375	
376	  const output: Record<string, unknown> = {};
377	  for (const [key, value] of Object.entries(schema)) {
378	    if (key === '$schema' || key === 'additionalProperties') continue;
379	    output[key] = toGeminiRestSchema(value);
380	  }
381	  return output;
382	}
