177	export async function resolveRouteCandidates(
178	  db: OracleDb,
179	  slot: ModelSlot,
180	): Promise<RouteCandidateResolution> {
181	  const { routeKey, effortKey, poolKey } = settingKeysForSlot(slot);
182	  const keys = [
183	    routeKey,
184	    ...(effortKey ? [effortKey] : []),
185	    ...(poolKey ? [poolKey] : []),
186	    ENFORCE_MODEL_CAPABILITIES_SETTING_KEY,
187	  ];
188	  const rows = await readSettings(db, keys);
189	
190	  const primaryValue = rows.get(routeKey);
191	  const primary = typeof primaryValue === 'string' ? primaryValue : null;
192	  if (!primary) throw new NoConfiguredModelError(slot, `${routeKey} is unset`);
193	
194	  const effort = effortKey && isReasoningEffort(rows.get(effortKey))
195	    ? (rows.get(effortKey) as ReasoningEffort)
196	    : undefined;
197	  const role = roleForSlot(slot);
198	  const enforceCaps = await enforceCapabilitiesEnabled(db);
199	
200	  const pool = poolKey && Array.isArray(rows.get(poolKey))
201	    ? (rows.get(poolKey) as unknown[]).filter((v): v is string => typeof v === 'string')
202	    : [];
203	
204	  if (poolKey && pool.length === 0) {
205	    throw new NoConfiguredModelError(slot, `${poolKey} is empty`);
206	  }
207	
208	  const probeIds = Array.from(new Set([primary, ...pool]));
209	  const capabilityMap = await loadCapabilityMap(db, probeIds);
210	  const primaryRoute = resolveWithKnownCaps(primary, role, effort, capabilityMap);
211	  if (!primaryRoute) throw new NoConfiguredModelError(slot, `${primary} cannot be resolved`);
212	  const primaryRouteCaps = await loadCapabilityMap(db, catalogIdsForRoute(primaryRoute));
213	  for (const [id, cap] of primaryRouteCaps) {
214	    capabilityMap.set(id, cap);
215	  }
216	
217	  const primaryCatalogIds = catalogIdsForRoute(primaryRoute);
218	  const primaryApprovedId =
219	    poolKey
220	      ? pool.find((id) => id === primary || primaryCatalogIds.includes(id))
221	      : primaryCatalogIds.find((id) => capabilityMap.has(id)) ?? primary;
222	
223	  if (poolKey && !primaryApprovedId) {
224	    throw new NoConfiguredModelError(
225	      slot,
226	      `${primary} resolves to ${primaryCatalogIds.join(' / ')} but is not in ${poolKey}`,
227	    );
228	  }
229	
230	  const ordered = poolKey
231	    ? [primaryApprovedId!, ...pool.filter((id) => id !== primaryApprovedId)]
232	    : [primary];
233	
234	  const candidates: RouteCandidate[] = [];
235	  const skipped: SkippedRouteCandidate[] = [];
236	  const seenConcrete = new Set<string>();
237	
238	  for (const [index, id] of ordered.entries()) {
239	    const route = index === 0
240	      ? primaryRoute
241	      : resolveWithKnownCaps(id, role, effort, capabilityMap);
242	    if (!route) {
243	      skipped.push({ slot, modelIdOrRouteId: id, reason: 'unresolvable model id' });
244	      continue;
245	    }
246	
247	    const concrete = providerModelIdForRoute(route);
248	    if (seenConcrete.has(concrete)) continue;
249	    seenConcrete.add(concrete);
250	
251	    const capMatch = capabilityForRoute(route, capabilityMap);
252	    if (enforceCaps) {
253	      if (!capMatch) {
254	        const err = new ModelCapabilityError(slot, concrete, ['catalog metadata']);
255	        if (index === 0) throw err;
256	        skipped.push({ slot, modelIdOrRouteId: id, reason: err.message });
257	        continue;
258	      }
259	      const missing = missingRequirements(normalizeProviderCapabilities(capMatch.cap), slot);
260	      if (missing.length > 0) {
261	        const err = new ModelCapabilityError(slot, capMatch.id, missing);
262	        if (index === 0) throw err;
263	        skipped.push({ slot, modelIdOrRouteId: id, reason: err.message });
264	        continue;
265	      }
266	    }
267	
268	    candidates.push({
269	      route,
270	      slot,
271	      isPrimary: index === 0,
272	      approvedModelId: poolKey ? id : capMatch?.id ?? concrete,
273	    });
274	  }
275	
276	  if (candidates.length === 0) {
277	    throw new NoConfiguredModelError(slot, 'all configured candidates were invalid');
278	  }
279	
280	  return { slot, candidates, skipped };
281	}
