1	/**
2	 * Settings value encoding ‚Äî single source of truth for keeping the `settings`
3	 * jsonb column single-encoded (Bug 4).
4	 *
5	 * `settings.value` is a Postgres `jsonb` column. Drizzle JSON-encodes whatever
6	 * JS value the writer passes, so:
7	 *   - writing the bare string `"off"`        ‚Üí stored jsonb `"off"`        (correct)
8	 *   - writing the bare array `["a","b"]`      ‚Üí stored jsonb `["a","b"]`    (correct)
9	 *   - writing the STRING `'"off"'` (already   ‚Üí stored jsonb `"\"off\""`   (DOUBLE-ENCODED)
10	 *     JSON-encoded) by mistake
11	 *   - writing the STRING `'["a","b"]'`        ‚Üí stored jsonb as a string    (DOUBLE-ENCODED)
12	 *
13	 * The consumers (`resolveRouteCandidates`, the admin picker loader) expect the
14	 * decoded value and silently break on the double-encoded form (an effort string
15	 * with literal quotes fails `isReasoningEffort`; a pool that is a string instead
16	 * of an array reads as an empty pool).
17	 *
18	 * `normalizeSettingValue` makes every write idempotent and self-healing: it
19	 * unwraps an accidental encode layer while leaving a correctly-typed value
20	 * untouched. The only legitimate scalar string settings (model ids like
21	 * `google/gemini-2.5-flash`, efforts like `off`, `sync`/`batch`) are never
22	 * themselves valid JSON documents ‚Äî they have no surrounding quotes/brackets ‚Äî
23	 * so they are never unwrapped.
24	 */
25	export function normalizeSettingValue(value: unknown): unknown {
26	  if (typeof value !== 'string') return value;
27	  const trimmed = value.trim();
28	  const looksEncoded =
29	    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
30	    trimmed.startsWith('[') ||
31	    trimmed.startsWith('{');
32	  if (!looksEncoded) return value;
33	  try {
34	    const decoded: unknown = JSON.parse(value);
35	    // Recurse so a (pathological) triple-encode also collapses; stop as soon as
36	    // the value is no longer an encoded-string wrapper.
37	    return normalizeSettingValue(decoded);
38	  } catch {
39	    return value;
40	  }
41	}
