43	/**
44	 * True when a value already stored in (or about to be written to) the jsonb
45	 * column is double-encoded ‚Äî i.e. a string that is itself a JSON document. Used
46	 * by the regression guard and by read-time health checks.
47	 */
48	export function isDoubleEncodedSettingValue(value: unknown): boolean {
49	  if (typeof value !== 'string') return false;
50	  const trimmed = value.trim();
51	  const looksEncoded =
52	    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
53	    trimmed.startsWith('[') ||
54	    trimmed.startsWith('{');
55	  if (!looksEncoded) return false;
56	  try {
57	    JSON.parse(value);
58	    return true;
59	  } catch {
60	    return false;
61	  }
62	}
